import{a as n}from"./chunk-432GMFUR.js";import{ca as i,eb as e,fb as a,gb as r,vb as o,zb as d}from"./chunk-S6EIKXLU.js";var p=(()=>{let s=class s{};s.\u0275fac=function(t){return new(t||s)},s.\u0275cmp=i({type:s,selectors:[["app-metodology"]],standalone:!0,features:[d],decls:29,vars:0,consts:[["title","Metodologia"],[1,"container"],[1,"section-title","mb-3"],[1,"mt-5"],[1,"me-1"],["href","./assets/metodologia.pdf","target","_blank"]],template:function(t,E){t&1&&(r(0,"app-header",0),e(1,"div",1)(2,"section")(3,"h1",2),o(4,"Modelo Conceitual"),a(),e(5,"p"),o(6," Para realizar as proje\xE7\xF5es de custos por Terra Ind\xEDgena, eixos e atividades, a calculadora de custos estabelece rela\xE7\xF5es estat\xEDsticas entre as caracter\xEDsticas das Terras Ind\xEDgenas, como tamanho, n\xFAmero de aldeias, n\xEDvel de amea\xE7a externa, complexidade de acesso, os poss\xEDveis n\xEDveis de implementa\xE7\xE3o das atividades previstas nos Planos de Gest\xE3o de Terras Ind\xEDgenas (PGTA), e seus custos m\xE9dios de implementa\xE7\xE3o. Cada atividade tem uma f\xF3rmula para prever os custos m\xE9dios com base (i) nos gastos hist\xF3ricos m\xE9dios de oito Terras Ind\xEDgenas que tiveram dados coletados e analisados, e (ii) em proje\xE7\xF5es de custos para cen\xE1rios hipot\xE9ticos que consideram mudan\xE7as poss\xEDveis nas caracter\xEDsticas das terras ind\xEDgenas e nos n\xEDveis de implementa\xE7\xE3o das atividades ao longo do tempo. Desta forma, \xE9 poss\xEDvel calcular os custos conforme os n\xEDveis de implementa\xE7\xE3o e as caracter\xEDsticas das terras ind\xEDgenas. "),a(),e(7,"p"),o(8," Os valores de custos s\xE3o obtidos pelas m\xE9dias do que observamos na coleta de dados (ver metodologia completa), feita com as organiza\xE7\xF5es ind\xEDgenas e organiza\xE7\xF5es de apoio que atuam diretamente na implementa\xE7\xE3o das atividades relacionadas aos PGTAs. Por exemplo, se para uma dada atividade uma terra ind\xEDgena gastou R$100.000 em um ano, e outra terra ind\xEDgena com as mesmas caracter\xEDsticas gastou R$200.000, o modelo far\xE1 a previs\xE3o de que o custo m\xE9dio ser\xE1 de R$150.000 no ano. Ressaltamos que a compara\xE7\xE3o do valor m\xE9dio previsto com o valor observado por uma terra espec\xEDfica sempre ter\xE1 um n\xEDvel de varia\xE7\xE3o em rela\xE7\xE3o \xE0 m\xE9dia (no exemplo, mais ou menos R$50.000). A implementa\xE7\xE3o de uma atividade pode ter um custo abaixo (acima) da m\xE9dia por ter sido mais (menos) eficiente, o que n\xE3o quer dizer que o modelo est\xE1 fazendo previs\xF5es \u201Cerradas\u201D, mas que h\xE1 uma diferen\xE7a entre o custo da atividade de uma organiza\xE7\xE3o e a m\xE9dia conjunta de todas as organiza\xE7\xF5es. Assim, metade das previs\xF5es ter\xE3o margem de erro \u201Cpara cima\u201D, e a outra metade ter\xE1 margem de erro \u201Cpara baixo\u201D. Quando somamos as diversas atividades de um PGTA, essa margem de erro tende a se cancelar, ou seja, o valor total de um PGTA ter\xE1 essa margem de erro suavizada. "),a(),e(9,"p"),o(10," Os valores s\xE3o categorizados segundo dois crit\xE9rios: (i) tipo de custo e; (ii) tipo de atividade. S\xE3o diferenciados dois tipos de custos: (i) valores de custos anuais de implementa\xE7\xE3o de atividades, chamados de \u201Cvalores correntes\u201D, como por exemplo sal\xE1rios, manuten\xE7\xE3o de equipamentos, compra de gasolina, etc; (ii) valores de custos de investimentos que s\xE3o feitos, por exemplo, a cada 5 anos, ou 10 anos, chamados de \u201Ccustos n\xE3o-recorrentes\u201D, como investimentos em equipamentos e constru\xE7\xF5es. Aten\xE7\xE3o: Algumas atividades dos custos n\xE3o-recorrentes n\xE3o possuem valores, pois as institui\xE7\xF5es consultadas n\xE3o tiveram esse tipo de custo em campo, e por isso n\xE3o foi poss\xEDvel prever valores para elas, o que n\xE3o quer dizer que os custos n\xE3o possam existir. "),a(),e(11,"p"),o(12," Os tipos de atividade s\xE3o agrupados por \u201CEixos Tem\xE1ticos\u201D (ver metodologia completa), definidos pelas equipes do Instituto Socioambiental (ISA) e Conserva\xE7\xE3o Estrat\xE9gica (CSF) com base nos PGTAs publicados das Terras Ind\xEDgenas (TIs) da Bacia do Rio Xingu. S\xE3o 8 eixos tem\xE1ticos, resultando em um total de 29 atividades. Para cada atividade foi definida uma m\xE9trica para avaliar seu n\xEDvel de implementa\xE7\xE3o. As m\xE9tricas s\xE3o definidas segundo tr\xEAs n\xEDveis gerais (i) sem implementa\xE7\xE3o; (ii) implementa\xE7\xE3o b\xE1sica; (iii) implementa\xE7\xE3o boa. Esses n\xEDveis foram subdivididos em valores intermedi\xE1rios, pois frequentemente o n\xEDvel de implementa\xE7\xE3o observado estava, por exemplo, entre o n\xEDvel sem implementa\xE7\xE3o e o n\xEDvel b\xE1sico. Para isso, foi utilizada uma escala que divide em 10 pontos a dist\xE2ncia entre n\xE3o haver nada implementado e haver uma implementa\xE7\xE3o b\xE1sica da atividade; e outros 10 pontos entre um n\xEDvel de implementa\xE7\xE3o b\xE1sico e o n\xEDvel \u201Cbom\u201D, que \xE9 o m\xE1ximo da atual an\xE1lise. Sendo assim, nossa escala total varia de 0 a 20. A escala de n\xEDvel de implementa\xE7\xE3o \xE9 uma vari\xE1vel chave que impacta nos custos. "),a(),e(13,"p"),o(14," Fazemos a distin\xE7\xE3o entre o n\xEDvel de implementa\xE7\xE3o atual e o n\xEDvel desejado (no final do ano de implementa\xE7\xE3o). Por exemplo, partir de um n\xEDvel de implementa\xE7\xE3o \u201C5\u201D para um n\xEDvel \u201C10\u201D ter\xE1 um custo menor do que partir do n\xEDvel \u201C2\u201D para o n\xEDvel \u201C10\u201D. Caso se queira obter o custo de simplesmente manter o n\xEDvel \u201C10\u201D, ambos os n\xEDveis atual e almejado devem ser definidos em \u201C10\u201D. "),a(),e(15,"p"),o(16," Por fim, as TIs est\xE3o divididas em dois grupos: o primeiro inclui 8 TIs com dados completos de custos e caracter\xEDsticas na base de dados da calculadora; e o segundo \xE9 formado por 12 TIs, tamb\xE9m localizados na Bacia do Xingu, por\xE9m, n\xE3o inclu\xEDdas na base de dados e com informa\xE7\xF5es apenas sobre as suas caracter\xEDsticas. Para essas terras, os valores s\xE3o extrapolados com um n\xEDvel maior de erro, e por isso recomendamos cuidado para considerar os valores previstos para o grupo de TIs extrapoladas. "),a()(),e(17,"section",3)(18,"h1",2),o(19,"COLETA DE DADOS"),a(),e(20,"p"),o(21," Foram coletados dados hist\xF3ricos (2018 a 2022) relativos a despesas com atividades em oito eixos tem\xE1ticos presentes na maioria dos PGTAs da regi\xE3o: governan\xE7a; fiscaliza\xE7\xE3o e prote\xE7\xE3o; fortalecimento cultural; gera\xE7\xE3o de renda; soberania alimentar; infraestruturas complementares (energia, comunica\xE7\xF5es e transportes); educa\xE7\xE3o complementar; sa\xFAde e saneamento complementares. Ao todo a calculadora tem informa\xE7\xF5es de 29 atividades, para as quais foram constru\xEDdas \u201Cm\xE9tricas\u201D que trazem informa\xE7\xF5es sobre o que \xE9 preciso a TI ter para a atividade estar no n\xEDvel de implementa\xE7\xE3o b\xE1sico e no n\xEDvel de implementa\xE7\xE3o bom. "),a(),e(22,"p"),o(23," Foram coletados dados para as Terras Ind\xEDgenas Apyterewa, Ba\xFA, Capoto-Jarina, Kayap\xF3, Menkragnoti, Panar\xE1, TIX (Batovi, Pequizal do Naruv\xF4tu, Xingu e Wawi) e Trincheira/Bacaj\xE1. As fontes de informa\xE7\xE3o foram as principais organiza\xE7\xF5es ind\xEDgenas e da sociedade civil parceira que atuam nestas Terras Ind\xEDgenas: Associa\xE7\xE3o Floresta Protegida (AFP), Associa\xE7\xE3o Iaki\xF4 Panar\xE1, Associa\xE7\xE3o Terra Ind\xEDgena do Xingu (ATIX), Instituto Kabu (IK), Instituto Raoni (IR), Instituto Socioambiental (ISA) e The Nature Conservancy. Foram tamb\xE9m realizadas entrevistas com representantes destas organiza\xE7\xF5es para a coleta de informa\xE7\xF5es sobre caracter\xEDsticas e contexto em que cada Terra Ind\xEDgena se encontra, como tamanho, n\xFAmero de aldeias, grau de amea\xE7a externa, complexidade de acesso, localiza\xE7\xE3o da sede da associa\xE7\xE3o, entre outras, assim como para a proje\xE7\xE3o de cen\xE1rios hipot\xE9ticos baseados na varia\xE7\xE3o destas caracter\xEDsticas e contexto. "),a(),e(24,"p")(25,"strong",4),o(26,"Saiba mais sobre a metodologia em"),a(),e(27,"a",5),o(28,"baixar pdf"),a()()()())},dependencies:[n]});let u=s;return u})();export{p as MetodologyComponent};
